def graph_to_dict(graph: CallGraph) -> dict:
    """Convert a CallGraph to the React Flow JSON dict."""
    nodes = []
    for node in graph.nodes.values():
        nodes.append({
            "id": node.id,
            "type": "custom",
            "data": {
                "label": node.label,
                "nodeType": node.node_type,
                "file": node.file,
                "lineno": node.lineno,
                "source": node.source,
            },
            "position": {"x": 0, "y": 0},
        })

    edges = []
    for edge in graph.edges:
        edges.append({
            "id": f"{edge.source}->{edge.target}",
            "source": edge.source,
            "target": edge.target,
            "data": {"crossFile": edge.cross_file},
        })

    return {"nodes": nodes, "edges": edges}

def export_graph(
    graph: Optional[CallGraph] = None,
    output_path: str = "explorer/public/graph_data.json",
) -> None:
    """Serialize *graph* to JSON and write to *output_path*.

    If *graph* is None, writes an empty graph so the frontend still loads.
    """
    if graph is None:
        data = {"nodes": [], "edges": []}
    else:
        data = graph_to_dict(graph)

    out = Path(output_path)
    out.parent.mkdir(parents=True, exist_ok=True)
    out.write_text(json.dumps(data, indent=2), encoding="utf-8")

def cmd_export(_args: argparse.Namespace) -> None:
    export_graph(output_path="explorer/public/graph_data.json")
    print("[VibeGraph] Export complete.")

async def get_graph():
    if not GRAPH_DATA_PATH.exists():
        raise HTTPException(status_code=404, detail="graph_data.json not found. Run 'python main.py analyze <path>' first.")
    return JSONResponse(content=json.loads(GRAPH_DATA_PATH.read_text()))

async def explain_node(req: ExplainRequest):
    agent = GroqAgent()
    try:
        result = agent.explain(
            node_label=req.node_label,
            source_code=req.source_code,
            level=req.level,
        )
    except Exception as exc:
        raise HTTPException(status_code=500, detail=str(exc))
    return {"explanation": result}

async def serve_spa(full_path: str):
    file_path = DIST_PATH / full_path
    if file_path.is_file():
        return FileResponse(str(file_path))
    return FileResponse(str(DIST_PATH / "index.html"))

class BasicReporter:
    """Generates a Markdown report from React Flow graph data (dict)."""

    def __init__(self, graph_data: dict):
        self.nodes: List[dict] = graph_data.get("nodes", [])
        self.edges: List[dict] = graph_data.get("edges", [])

    # ------------------------------------------------------------------
    # Public API
    # ------------------------------------------------------------------

    def generate(self) -> str:
        sections = [
            "# VibeGraph — Code Analysis Report\n",
            self._summary_section(),
            self._nodes_by_file_section(),
            self._edges_section(),
        ]
        return "\n".join(sections)

    # ------------------------------------------------------------------
    # Private helpers
    # ------------------------------------------------------------------

    def _summary_section(self) -> str:
        num_nodes = len(self.nodes)
        num_edges = len(self.edges)
        files = {n["data"]["file"] for n in self.nodes}
        return (
            f"## Summary\n\n"
            f"| Metric | Count |\n"
            f"|--------|-------|\n"
            f"| Files analyzed | {len(files)} |\n"
            f"| Nodes (functions + classes + entries) | {num_nodes} |\n"
            f"| Call edges | {num_edges} |\n"
        )

    def _nodes_by_file_section(self) -> str:
        by_file: Dict[str, List[dict]] = {}
        for node in self.nodes:
            f = node["data"]["file"]
            by_file.setdefault(f, []).append(node)

        lines = ["## Nodes by File\n"]
        for file_path, nodes in sorted(by_file.items()):
            lines.append(f"### `{file_path}`\n")
            for node in sorted(nodes, key=lambda n: n["data"]["lineno"]):
                icon = {"function": "⚡", "class": "🏗️", "entry": "🚀"}.get(
                    node["data"]["nodeType"], "•"
                )
                lines.append(
                    f"- {icon} **{node['data']['label']}** (line {node['data']['lineno']})"
                )
            lines.append("")

        return "\n".join(lines)

    def _edges_section(self) -> str:
        if not self.edges:
            return "## Call Edges\n\n*No call relationships found.*\n"

        id_to_label = {n["id"]: n["data"]["label"] for n in self.nodes}

        lines = ["## Call Edges\n"]
        for edge in self.edges:
            src_label = id_to_label.get(edge["source"], edge["source"])
            tgt_label = id_to_label.get(edge["target"], edge["target"])
            cross = " *(cross-file)*" if edge.get("data", {}).get("crossFile") else ""
            lines.append(f"- `{src_label}` → `{tgt_label}`{cross}")

        lines.append("")
        return "\n".join(lines)

